import { useQuery } from '@tanstack/react-query';
import React, { useState } from 'react'
import { Img_URL, fetchMovie } from '../../utils/fetchApi';
import { Link } from 'react-router-dom';
import  "../MovieCategory/popular.scss"
const Popular = () => {
    let popularMoviesItem =[];

    const [page,setPage]=useState(1);

   const loadMoreHandle=()=>{

   }
    const { data: Popular } = useQuery({
        queryKey: ["Movie", "Popular"],
        keepPreviousData: true,
        staleTime:60000,
        queryFn: () =>
          fetchMovie("popular",`${page}`).then((res) => {
            return res.results;
          }),
      });

      popularMoviesItem.push(Popular);
      console.log(popularMoviesItem);
  return (
    <div className="Popular">
          <h1>Popular Movies</h1>
          <div>
          {popularMoviesItem?.map((item) => (
              <Link to={`/movie/${item.id}`} className="card" key={item.title}>
                <img src={`${Img_URL}${item.poster_path}`} alt="img" />
              </Link>
          ))}
          </div>
          <button onClick={loadMoreHandle}>More</button>
        </div>
  )
}

export default Popular
